import React, { useEffect, useState } from 'react';
import { get, put } from '../api';

const AddressesList = () => {
  const [addresses, setAddresses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [editingId, setEditingId] = useState(null);
  const [editingValues, setEditingValues] = useState({
    recipientName: '',
    houseOrFlatNo: '',
    streetOrLocality: '',
    city: '',
    pinCode: '',
  });
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);

  const loadAddresses = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/addresses');
      setAddresses(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load addresses.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAddresses();
  }, []);

  const handleRefresh = () => {
    loadAddresses();
  };

  const handleEdit = (address) => {
    setEditingId(address.id);
    setEditingValues({
      recipientName: address.recipientName || '',
      houseOrFlatNo: address.houseOrFlatNo || '',
      streetOrLocality: address.streetOrLocality || '',
      city: address.city || '',
      pinCode: address.pinCode || '',
    });
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleSave = async () => {
    if (!editingId) return;
    setActionError(null);
    setSuccessMessage(null);

    try {
      await put(`/api/admin-lists/addresses/${editingId}`, {
        ...editingValues,
      });
      setSuccessMessage('Saved successfully.');
      setEditingId(null);
      setEditingValues({
        recipientName: '',
        houseOrFlatNo: '',
        streetOrLocality: '',
        city: '',
        pinCode: '',
      });
      await loadAddresses();
    } catch (err) {
      console.error(err);
      setActionError('Unable to update details.');
    }
  };

  return (
    <div>
      <h2>Delivery Address Master</h2>
      <div style={{ marginBottom: 12 }}>
        <button onClick={handleRefresh} disabled={loading}>
          Refresh
        </button>
      </div>
      {loading && <p>Loading addresses...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}

      {!loading && !error && (
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Parent ID</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Recipient Name</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>House / Flat No</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Street / Locality</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>City</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>PIN Code</th>
              <th style={{ border: '1px solid #ccc', padding: '8px' }}>Actions</th>
            </tr>
          </thead>
          <tbody>
            {addresses.map((address) => (
              <tr key={address.id}>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.id}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.recipientName || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.houseOrFlatNo || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.streetOrLocality || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.city || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>{address.pinCode || 'None'}</td>
                <td style={{ border: '1px solid #ccc', padding: '8px' }}>
                  <button onClick={() => handleEdit(address)}>Edit</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {editingId && (
        <div style={{ marginTop: 24, maxWidth: 600 }}>
          <h3>Edit Parent #{editingId}</h3>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Recipient Name</label>
            <input
              type="text"
              value={editingValues.recipientName}
              onChange={(e) => setEditingValues((prev) => ({ ...prev, recipientName: e.target.value }))}
              style={{ width: '100%', padding: 8, marginBottom: 12 }}
            />
            <label style={{ display: 'block', marginBottom: 4 }}>House / Flat No</label>
            <input
              type="text"
              value={editingValues.houseOrFlatNo}
              onChange={(e) => setEditingValues((prev) => ({ ...prev, houseOrFlatNo: e.target.value }))}
              style={{ width: '100%', padding: 8, marginBottom: 12 }}
            />
            <label style={{ display: 'block', marginBottom: 4 }}>Street / Locality</label>
            <input
              type="text"
              value={editingValues.streetOrLocality}
              onChange={(e) => setEditingValues((prev) => ({ ...prev, streetOrLocality: e.target.value }))}
              style={{ width: '100%', padding: 8, marginBottom: 12 }}
            />
            <label style={{ display: 'block', marginBottom: 4 }}>City</label>
            <input
              type="text"
              value={editingValues.city}
              onChange={(e) => setEditingValues((prev) => ({ ...prev, city: e.target.value }))}
              style={{ width: '100%', padding: 8, marginBottom: 12 }}
            />
            <label style={{ display: 'block', marginBottom: 4 }}>PIN Code</label>
            <input
              type="text"
              value={editingValues.pinCode}
              onChange={(e) => setEditingValues((prev) => ({ ...prev, pinCode: e.target.value }))}
              style={{ width: '100%', padding: 8, marginBottom: 12 }}
            />
          </div>
          <button onClick={handleSave} style={{ marginRight: 8 }}>
            Save
          </button>
          <button
            onClick={() => {
              setEditingId(null);
              setEditingValues({
                recipientName: '',
                houseOrFlatNo: '',
                streetOrLocality: '',
                city: '',
                pinCode: '',
              });
            }}
          >
            Cancel
          </button>
        </div>
      )}
    </div>
  );
};

export default AddressesList;
